  description = 'Partners connect hands or shoulders and exchange controlled push-pull pressure from an athletic stance.',
  participant_structure = 'pairs',
  card_summary = 'Partner Push-Pull Athletic Stance is a two-person paired exercise for anti-movement trunk control, pressure management, and stance recovery under external force. Use it when the goal is partner timing, shared force, or live stimulus quality rather than group chaos or fatigue chasing.',
  coach_language = 'Primary subrole: trunk_pelvis_anti_movement_control. Coach Partner Push-Pull Athletic Stance as pair-specific work: define roles, cap partner force, use clear stop commands, and preserve quality before competition.',
  athlete_language = 'Communicate, match your partner, and own the reset.',
  movement_family = 'Manual push-pull control',
  primary_phase_key = 'resilience',
  phase_subrole = 'trunk_pelvis_anti_movement_control',
  primary_order_slot = 'partner_push_pull_athletic_stance',
  default_sets = 2,
  default_reps = NULL,
  default_work_seconds = 20,
  default_rest_seconds = 40,
  est_seconds_per_set = 80,
  movement_requirements = '{"primary_joint_actions":["trunk anti-movement","hip stability","breathing under tension"],"primary_tissues":["core","spine","hip"],"breathing_demand":"moderate","balance_demand":"high","coordination_demand":"moderate","impact_level":1,"pair_profile":{"requires_exactly_two_people":true,"roles":["athlete","partner"],"partner_input":"cue, toss, resistance, assistance, pressure, or perturbation as defined by the card","group_size_note":"Designed for pairs only; do not require groups of three or more."},"anti_movement_profile":{"external_force_source":"partner","force_rule":"predictable, progressive, and agreed before the rep","rotation_tolerance":"minimal trunk or pelvis leak before reset"}}'::jsonb,
  coaching_execution = '{"movement_description":"Partners connect hands or shoulders and exchange controlled push-pull pressure from an athletic stance.","setup":["Pair athletes by size, skill, maturity, and ability to follow stop commands.","Define the athlete role, partner role, allowed contact/resistance, and the stop word before the first rep.","Set safe spacing and clear the area of obstacles; use cones, mat, line, band, or ball as needed."],"execution_steps":["Athlete performs: Partners connect hands or shoulders and exchange controlled push-pull pressure from an athletic stance.","Partner supplies only the agreed cue, toss, resistance, support, or perturbation and stays attentive to the athlete''s posture.","Reset after each rep or short work window, then switch roles so both partners receive the same quality exposure."],"coach_cues":["Talk before force.","Match the partner, do not beat the partner.","Clean rep, clean reset.","Stop on sloppy spacing or posture."],"common_faults":["Partner adds too much force or surprise","Athlete rushes the rep to win instead of solving the movement problem","Spacing drifts and the pair loses a safe lane","Breath holding, shrugging, or trunk collapse under partner input","Perturbation becomes a challenge contest instead of controlled exposure"],"breathing_cues":["Exhale through effort or contact","Do not hold breath to survive partner force","Recover breathing before switching roles"],"quality_gate":"The rep counts only if both partners keep the agreed role, safe spacing, communication, posture, and controlled reset.","stop_signs":["Pain","dizziness","panic step","fall risk","partner surprise force","lost spacing","dropped implement near feet","speed or posture decay"]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Sport skill work","Strength accessories","Conditioning only if quality is preserved"],"pairs_well_after":["General warm-up","Dynamic mobility","Solo pattern rehearsal"],"good_for_sessions":["general_warmup","resilience","control_landing"],"avoid_before":[],"avoid_after":[],"do_not_use_when":["Partners cannot follow stop commands or keep the input controlled","The area is crowded or spacing cannot be protected","The athlete has pain, fear, dizziness, or unsafe compensation during the solo version","The session goal requires quiet individual practice rather than partner interaction"]}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":[],"internal_notes":["Film both roles, not only the athlete role.","Demo the partner input separately before full-speed reps.","Show the stop command and role switch in any media clip."]}'::jsonb,
  updated_at = now()
WHERE slug = 'partner-push-pull-athletic-stance';

INSERT INTO coaching.exercise_phase_profile (
  exercise_id, phase_id, fit_weight, role, order_slot, order_index,
  freshness_required, fatigue_sensitivity, fatigue_cost, technical_complexity, impact_level, intensity_ceiling
)
SELECT e.id, sp.id, 5, 'primary', 'partner_push_pull_athletic_stance', pos.order_index,
  FALSE, 3, 2,
  3, 1, 'moderate'
FROM coaching.exercise e
JOIN coaching.session_phase sp ON sp.key = 'resilience'
JOIN coaching.phase_order_slot pos ON pos.key = 'partner_push_pull_athletic_stance' AND pos.phase_id = sp.id
WHERE e.slug = 'partner-push-pull-athletic-stance'
ON CONFLICT (exercise_id, phase_id) DO UPDATE SET
  role = EXCLUDED.role,
  order_slot = EXCLUDED.order_slot,
  order_index = EXCLUDED.order_index,
  fit_weight = EXCLUDED.fit_weight,
  freshness_required = EXCLUDED.freshness_required,
  fatigue_sensitivity = EXCLUDED.fatigue_sensitivity,
  fatigue_cost = EXCLUDED.fatigue_cost,
  technical_complexity = EXCLUDED.technical_complexity,
  impact_level = EXCLUDED.impact_level,
  intensity_ceiling = EXCLUDED.intensity_ceiling;

