-- Partner Hand-Fighting Footwork (partner-hand-fighting-footwork) [insert]
UPDATE coaching.exercise SET
  name = 'Partner Hand-Fighting Footwork',
  description = 'Partners use light hand-fighting contact while maintaining stance, footwork, and safe spacing.',
  participant_structure = 'pairs',
  card_summary = 'Partner Hand-Fighting Footwork is a two-person paired exercise for hand pressure, stance control, lateral footwork, and live opponent reading. Use it when the goal is partner timing, shared force, or live stimulus quality rather than group chaos or fatigue chasing.',
