  default_rest_seconds = 35,
  est_seconds_per_set = 80,
  movement_requirements = '{"primary_joint_actions":["hip flexion-extension","ankle stiffness","direction change"],"primary_tissues":["foot","ankle","knee"],"breathing_demand":"low_to_moderate","balance_demand":"high","coordination_demand":"high","impact_level":1,"pair_profile":{"requires_exactly_two_people":true,"roles":["athlete","partner"],"partner_input":"cue, toss, resistance, assistance, pressure, or perturbation as defined by the card","group_size_note":"Designed for pairs only; do not require groups of three or more."},"reactive_output_profile":{"stimulus_type":"partner visual, tactile, or ball cue","amplitude_cap":"short, safe, and repeatable","quality_rule":"stop before timing, speed, catch quality, or decision quality degrades"}}'::jsonb,
  coaching_execution = '{"movement_description":"Partners use light hand-fighting contact while maintaining stance, footwork, and safe spacing.","setup":["Pair athletes by size, skill, maturity, and ability to follow stop commands.","Define the athlete role, partner role, allowed contact/resistance, and the stop word before the first rep.","Set safe spacing and clear the area of obstacles; use cones, mat, line, band, or ball as needed."],"execution_steps":["Athlete performs: Partners use light hand-fighting contact while maintaining stance, footwork, and safe spacing.","Partner supplies only the agreed cue, toss, resistance, support, or perturbation and stays attentive to the athlete''s posture.","Reset after each rep or short work window, then switch roles so both partners receive the same quality exposure."],"coach_cues":["Talk before force.","Match the partner, do not beat the partner.","Clean rep, clean reset.","Stop on sloppy spacing or posture."],"common_faults":["Partner adds too much force or surprise","Athlete rushes the rep to win instead of solving the movement problem","Spacing drifts and the pair loses a safe lane","Breath holding, shrugging, or trunk collapse under partner input"],"breathing_cues":["Exhale through effort or contact","Do not hold breath to survive partner force","Recover breathing before switching roles"],"quality_gate":"The rep counts only if both partners keep the agreed role, safe spacing, communication, posture, and controlled reset.","stop_signs":["Pain","dizziness","panic step","fall risk","partner surprise force","lost spacing","dropped implement near feet","speed or posture decay"]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Sport skill work","Strength accessories","Conditioning only if quality is preserved"],"pairs_well_after":["General warm-up","Dynamic mobility","Solo pattern rehearsal"],"good_for_sessions":["general_warmup","movement_intelligence","team_skill_prep","change_of_direction","wrestling_or_gymnastics_prep"],"avoid_before":[],"avoid_after":[],"do_not_use_when":["Partners cannot follow stop commands or keep the input controlled","The area is crowded or spacing cannot be protected","The athlete has pain, fear, dizziness, or unsafe compensation during the solo version","The session goal requires quiet individual practice rather than partner interaction"]}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":[],"internal_notes":["Film both roles, not only the athlete role.","Demo the partner input separately before full-speed reps.","Show the stop command and role switch in any media clip."]}'::jsonb,
  updated_at = now()
WHERE slug = 'partner-hand-fighting-footwork';

