-- Why-layer education
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_works, why_it_matters, why_it_goes_here,
  programming_guidance, common_misuse, scaling_guidance
)
SELECT
  'exercise', e.slug, e.id, e.name, e.card_summary,
  e.description,
  v.why_works,
  'Develops partner timing, shared force, perception-action quality, and communication across paired Output, Skill, Resilience, and Capacity work.',
  v.why_here,
  v.best_placement,
  v.misuse,
  v.scale_guidance
FROM (VALUES
  ('partner-medicine-ball-chest-pass', 'The partner creates a constraint that a solo drill cannot fully reproduce: live timing, shared resistance, external pressure, or a real visual cue. That makes Partner Medicine Ball Chest Pass valuable for horizontal upper-body power, trunk stiffness, visual tracking, and safe partner timing because the athlete must organize posture, force, perception, and communication at the same time.', 'Belongs in Output because the task expresses speed, power, throwing, acceleration, cutting, or reactive athleticism at high quality while fresh.', 'Use after warm-up and movement prep, before heavy strength or conditioning. Keep volume low, rest fully, and stop when speed, accuracy, posture, or decision quality drops.', 'The main mistake is letting the partner make the drill random, too heavy, or too competitive. Keep the input matched to the athlete and stop before accuracy, posture, spacing, or communication breaks. Do not extend sets until breathing or fatigue decides the outcome; this is speed/power quality, not conditioning.', 'Progress only one variable at a time: partner force, implement load, speed, distance, unpredictability, range, duration, or contact intensity. Regress by removing the live partner input first.'),
  ('partner-medicine-ball-overhead-toss', 'The partner creates a constraint that a solo drill cannot fully reproduce: live timing, shared resistance, external pressure, or a real visual cue. That makes Partner Medicine Ball Overhead Toss valuable for overhead force transfer, trunk extension-to-flexion control, and catch readiness because the athlete must organize posture, force, perception, and communication at the same time.', 'Belongs in Output because the task expresses speed, power, throwing, acceleration, cutting, or reactive athleticism at high quality while fresh.', 'Use after warm-up and movement prep, before heavy strength or conditioning. Keep volume low, rest fully, and stop when speed, accuracy, posture, or decision quality drops.', 'The main mistake is letting the partner make the drill random, too heavy, or too competitive. Keep the input matched to the athlete and stop before accuracy, posture, spacing, or communication breaks. Do not extend sets until breathing or fatigue decides the outcome; this is speed/power quality, not conditioning.', 'Progress only one variable at a time: partner force, implement load, speed, distance, unpredictability, range, duration, or contact intensity. Regress by removing the live partner input first.'),
